INSERT INTO sales_transactions (
  property_id, sale_date, sold_price, cap_rate, stated_cap_rate,
  initial_cap_rate, buyer_name, seller_name, data_source, notes
)
SELECT
  ns.property_id, ns.sale_date, ns.sold_price::numeric, ns.cap_rate::numeric,
  ns.stated_cap_rate::numeric, ns.initial_cap_rate::numeric,
  ns.buyer_name, ns.seller_name, ns.data_source, ns.notes
FROM new_sales ns
WHERE NOT EXISTS (
  SELECT 1 FROM sales_transactions st
  WHERE st.property_id = ns.property_id
    AND st.sale_date = ns.sale_date
    AND ABS(st.sold_price - ns.sold_price::numeric) < 100  -- $100 tolerance
);

